import { useEffect, useRef, useState } from "react";
import { computeScrollState, type ScrollState } from "./helper"

type Options = {
    threshold?: number;
    target?: HTMLElement | null;
};

export default function useScrollState(options: Options = {}) {
    const { threshold = 60, target } = options;

    const lastY = useRef(0);

    const [scrollState, setScrollState] = useState<ScrollState>({
        y: 0,
        isScrolled: false,
        direction: "up",
    });

    useEffect(() => {
        const el = target ?? window;

        const getScrollY = () =>
            el === window
                ? window.scrollY
                : (el as HTMLElement).scrollTop;

        const onScroll = () => {
            const y = getScrollY();
            if (y === lastY.current) return;

            const prevY = lastY.current;
            lastY.current = y;

            setScrollState(
                computeScrollState(prevY, y, threshold)
            );
        };

        el.addEventListener("scroll", onScroll, { passive: true });
        return () => el.removeEventListener("scroll", onScroll);
    }, [threshold, target]);

    return { scrollState };
}